(() => {
    type ICircular = {name: string; child?: ICircular};
    return {build: () => createValidate<ICircular>(), buildErrors: () => noErrs(createGetValidationErrors<ICircular>())};
  })()

() => {
    const ic = RT.circular((self) => RT.object({name: RT.string(), child: RT.optional(self)}));
    return createValidate(ic);
  }

(() => {
    type ICircular = {name: string; child?: ICircular};
    return {
      build: () => {
        const check = typia.createIs<ICircular>();
        return (v) => check(v);
      },
      buildErrors: () => {
        const val = typia.createValidate<ICircular>();
        return (v) => val(v).success;
      },
    };
  })()

c(
    Type.Recursive((This) => Type.Object({name: Type.String(), child: Type.Optional(This)}))
  )

c(z.lazy(() => {
    const schema: z.ZodType = z.object({name: z.string(), child: z.lazy(() => schema).optional()});
    return schema;
  }))
